SELECT
id, type, title, message, recipient_id, is_read,
ref_id, ref_type, created_at, updated_at, is_deleted
FROM notifications
WHERE recipient_id = #{recipientId}
AND is_deleted = 0

    AND type = #{type}


    AND is_read = #{isRead}

ORDER BY created_at DESC

SELECT COUNT(1) > 0
FROM notifications
WHERE type = 'SOLAR_ANOMALY'
AND ref_id = #{deviceId}
AND YEAR(created_at) = #{recordYear}
AND MONTH(created_at) = #{recordMonth}
AND is_deleted = 0

SELECT COUNT(1) > 0
FROM notifications
WHERE type = 'CONTRACT_EXPIRY'
AND ref_id = #{contractId}
AND recipient_id = #{recipientId}
AND is_deleted = 0
